RoundedRectangle.OnClickCode:
if( gr_heatmap.isVisible() ){
	gr_heatmap.setVisible(false);
	gr_chartsYear.setVisible(true);
	uI_Results.v_selectedChartText = "de jaarprofielen";
}
else{
	gr_heatmap.setVisible(true);
	gr_chartsYear.setVisible(false);
	uI_Results.v_selectedChartText = "de consumptie heatmap";
}

BasicProperties.ActionCode:
switch(rb_exportUnit.getValue()){
	case 0:
		p_selectedExportUnit = "kWh";
		break;
	case 1:
		p_selectedExportUnit = "kW";	
		break;
	default:
		throw new RuntimeException("Unsupported unit type selected!");
}
